DEFINE TABLE OVERWRITE billing SCHEMAFULL
    PERMISSIONS 
        FOR select WHERE fn::has_permission(<string>$auth.id, 'billing.view_all', NONE) OR
                        fn::has_permission(<string>$auth.id, 'billing.view_own', <string>tenant) OR
                        fn::has_permission(<string>$auth.id, 'billing.view_customers', <string>tenant)
        FOR create WHERE fn::has_permission(<string>$auth.id, 'billing.create_all', NONE) OR
                        fn::has_permission(<string>$auth.id, 'billing.create_customers', <string>tenant)
        FOR update WHERE fn::has_permission(<string>$auth.id, 'billing.update_all', NONE) OR
                        fn::has_permission(<string>$auth.id, 'billing.update_own', <string>tenant) OR
                        fn::has_permission(<string>$auth.id, 'billing.update_customers', <string>tenant)
        FOR delete WHERE fn::has_permission(<string>$auth.id, 'billing.delete_all', NONE);
DEFINE FIELD OVERWRITE tenant ON TABLE billing TYPE record<tenant>;
DEFINE FIELD OVERWRITE responsible_party ON TABLE billing TYPE record<tenant>; -- Who actually pays
DEFINE FIELD OVERWRITE billing_period_start ON TABLE billing TYPE datetime;
DEFINE FIELD OVERWRITE billing_period_end ON TABLE billing TYPE datetime;
DEFINE FIELD OVERWRITE amount ON TABLE billing TYPE number ASSERT $value >= 0;
DEFINE FIELD OVERWRITE currency ON TABLE billing TYPE string DEFAULT 'USD';
DEFINE FIELD OVERWRITE status ON TABLE billing TYPE string ASSERT $value IN ['draft', 'pending', 'paid', 'overdue', 'cancelled'] DEFAULT 'draft';
DEFINE FIELD OVERWRITE invoice_number ON TABLE billing TYPE string;
DEFINE FIELD OVERWRITE msp_commission ON TABLE billing TYPE option<number>;
DEFINE FIELD OVERWRITE payment_due_date ON TABLE billing TYPE datetime;
DEFINE FIELD OVERWRITE created_at ON TABLE billing TYPE datetime DEFAULT time::now();
DEFINE FIELD OVERWRITE updated_at ON TABLE billing TYPE datetime DEFAULT time::now();

DEFINE TABLE OVERWRITE msp_customer_relationship SCHEMAFULL
    PERMISSIONS 
        FOR select WHERE fn::has_permission(<string>$auth.id, 'msp.view_all', NONE) OR
                        fn::has_permission(<string>$auth.id, 'msp.view_own', <string>msp_tenant)
        FOR create, update, delete WHERE fn::has_permission(<string>$auth.id, 'msp.manage_relationships', <string>msp_tenant) OR
                                        fn::has_permission(<string>$auth.id, 'system.manage', NONE);
DEFINE FIELD OVERWRITE msp_tenant ON TABLE msp_customer_relationship TYPE record<tenant>;
DEFINE FIELD OVERWRITE customer_tenant ON TABLE msp_customer_relationship TYPE record<tenant>;
DEFINE FIELD OVERWRITE relationship_type ON TABLE msp_customer_relationship TYPE string ASSERT $value IN ['managed', 'partner', 'reseller'] DEFAULT 'managed';
DEFINE FIELD OVERWRITE billing_arrangement ON TABLE msp_customer_relationship TYPE string ASSERT $value IN ['msp_pays', 'customer_pays', 'split'] DEFAULT 'msp_pays';
DEFINE FIELD OVERWRITE commission_rate ON TABLE msp_customer_relationship TYPE option<number>;
DEFINE FIELD OVERWRITE contract_start ON TABLE msp_customer_relationship TYPE datetime DEFAULT time::now();
DEFINE FIELD OVERWRITE contract_end ON TABLE msp_customer_relationship TYPE option<datetime>;
DEFINE FIELD OVERWRITE status ON TABLE msp_customer_relationship TYPE string ASSERT $value IN ['active', 'suspended', 'terminated'] DEFAULT 'active';
DEFINE FIELD OVERWRITE created_at ON TABLE msp_customer_relationship TYPE datetime DEFAULT time::now();
DEFINE TABLE OVERWRITE role SCHEMAFULL
    PERMISSIONS 
        FOR select WHERE fn::has_permission(<string>$auth.id, 'role.view_all', NONE) OR fn::has_permission(<string>$auth.id, 'role.view_own_tenant', NONE)
        FOR create, update, delete WHERE fn::has_permission(<string>$auth.id, 'system.manage', NONE);
DEFINE FIELD OVERWRITE name ON TABLE role TYPE string ASSERT $value != NONE;
DEFINE FIELD OVERWRITE description ON TABLE role TYPE string;
DEFINE FIELD OVERWRITE level ON TABLE role TYPE number ASSERT $value >= 1 AND $value <= 5;
DEFINE FIELD OVERWRITE permissions ON TABLE role TYPE array<string>;
DEFINE FIELD OVERWRITE created_at ON TABLE role TYPE datetime DEFAULT time::now();

DEFINE TABLE OVERWRITE script_migration SCHEMAFULL
    PERMISSIONS
        FOR select FULL
        FOR create, update, delete NONE;

DEFINE FIELD OVERWRITE script_name ON script_migration TYPE string;
DEFINE FIELD OVERWRITE executed_at ON script_migration TYPE datetime VALUE time::now() READONLY;
DEFINE FIELD OVERWRITE checksum ON script_migration TYPE option<string>;

DEFINE TABLE OVERWRITE tenant SCHEMAFULL
    PERMISSIONS 
        FOR select WHERE fn::has_permission(<string>$auth.id, 'tenant.view_all', NONE) OR 
                        fn::has_permission(<string>$auth.id, 'tenant.view_own', <string>id) OR
                        fn::has_permission(<string>$auth.id, 'tenant.view_customers', <string>id)
        FOR create WHERE fn::has_permission(<string>$auth.id, 'tenant.create', NONE)
        FOR update WHERE fn::has_permission(<string>$auth.id, 'tenant.manage_all', NONE) OR
                        fn::has_permission(<string>$auth.id, 'tenant.update_own', <string>id) OR
                        fn::has_permission(<string>$auth.id, 'tenant.update_customers', <string>id)
        FOR delete WHERE fn::has_permission(<string>$auth.id, 'tenant.delete', NONE);
DEFINE FIELD OVERWRITE name ON TABLE tenant TYPE string ASSERT $value != NONE;
DEFINE FIELD OVERWRITE slug ON TABLE tenant TYPE string ASSERT $value != NONE;
DEFINE FIELD OVERWRITE tenant_type ON TABLE tenant TYPE string ASSERT $value IN ['super_admin', 'msp', 'customer'] DEFAULT 'customer';
DEFINE FIELD OVERWRITE parent_tenant ON TABLE tenant TYPE option<record<tenant>>;
DEFINE FIELD OVERWRITE msp_tenant ON TABLE tenant TYPE option<record<tenant>>;
DEFINE FIELD OVERWRITE contact_email ON TABLE tenant TYPE string;
DEFINE FIELD OVERWRITE contact_phone ON TABLE tenant TYPE option<string>;
DEFINE FIELD OVERWRITE billing_enabled ON TABLE tenant TYPE bool DEFAULT true;
DEFINE FIELD OVERWRITE billing_responsibility ON TABLE tenant TYPE string ASSERT $value IN ['self', 'msp', 'parent'] DEFAULT 'self';
DEFINE FIELD OVERWRITE status ON TABLE tenant TYPE string ASSERT $value IN ['active', 'suspended', 'inactive'] DEFAULT 'active';
DEFINE FIELD OVERWRITE settings ON TABLE tenant TYPE object DEFAULT {};
DEFINE FIELD OVERWRITE created_at ON TABLE tenant TYPE datetime DEFAULT time::now();
DEFINE FIELD OVERWRITE updated_at ON TABLE tenant TYPE datetime DEFAULT time::now();
DEFINE TABLE OVERWRITE token TYPE NORMAL SCHEMAFULL 
    PERMISSIONS 
        FOR select WHERE fn::has_permission(<string>$auth.id, 'token.view_all', NONE) OR
                        fn::has_permission(<string>$auth.id, 'token.view_own', <string>tenant) OR
                        fn::has_permission(<string>$auth.id, 'token.view_customers', <string>tenant)
        FOR create WHERE fn::has_permission(<string>$auth.id, 'token.create_all', NONE) OR
                        fn::has_permission(<string>$auth.id, 'token.create_customers', <string>tenant)
        FOR update WHERE fn::has_permission(<string>$auth.id, 'token.update_all', NONE) OR
                        fn::has_permission(<string>$auth.id, 'token.update_own', <string>tenant) OR
                        fn::has_permission(<string>$auth.id, 'token.update_customers', <string>tenant)
        FOR delete WHERE fn::has_permission(<string>$auth.id, 'token.delete_all', NONE);

DEFINE FIELD OVERWRITE tenant ON token TYPE record<tenant>;
DEFINE FIELD OVERWRITE type ON token TYPE set<'agent'>;
DEFINE FIELD OVERWRITE jwt ON token TYPE string;
DEFINE FIELD OVERWRITE type[*] ON token TYPE 'agent' PERMISSIONS FULL;
DEFINE FIELD OVERWRITE owner ON token TYPE record<user>;
DEFINE FIELD OVERWRITE created_at ON TABLE billing TYPE datetime DEFAULT time::now();
DEFINE FIELD OVERWRITE updated_at ON TABLE billing TYPE datetime DEFAULT time::now();

-- Indexes for performance
DEFINE INDEX OVERWRITE tenant_slug_idx ON TABLE tenant COLUMNS slug UNIQUE;
DEFINE INDEX OVERWRITE user_email_idx ON TABLE user COLUMNS email UNIQUE;
DEFINE INDEX OVERWRITE user_tenant_idx ON TABLE user_role COLUMNS user, tenant;
DEFINE INDEX OVERWRITE msp_customer_idx ON TABLE msp_customer_relationship COLUMNS msp_tenant, customer_tenant UNIQUE;

DEFINE TABLE OVERWRITE user SCHEMAFULL
    PERMISSIONS 
        FOR select WHERE $auth.id = id OR 
                        fn::has_permission(<string>$auth.id, 'user.view_all', NONE) OR
                        fn::has_permission(<string>$auth.id, 'user.view_own_tenant', <string>primary_tenant) OR
                        fn::has_permission(<string>$auth.id, 'user.view_customers', <string>primary_tenant)
        FOR create WHERE fn::has_permission(<string>$auth.id, 'user.create_all', NONE) OR
                        fn::has_permission(<string>$auth.id, 'user.create_own_tenant', <string>primary_tenant) OR
                        fn::has_permission(<string>$auth.id, 'user.create_customers', <string>primary_tenant)
        FOR update WHERE $auth.id = id OR
                        fn::has_permission(<string>$auth.id, 'user.update_all', NONE) OR
                        fn::has_permission(<string>$auth.id, 'user.update_own_tenant', <string>primary_tenant) OR
                        fn::has_permission(<string>$auth.id, 'user.update_customers', <string>primary_tenant)
        FOR delete WHERE fn::has_permission(<string>$auth.id, 'user.delete_all', NONE) OR
                        fn::has_permission(<string>$auth.id, 'user.delete_own_tenant', <string>primary_tenant) OR
                        fn::has_permission(<string>$auth.id, 'user.delete_customers', <string>primary_tenant);
DEFINE FIELD OVERWRITE email ON TABLE user TYPE string ASSERT string::is::email($value);
DEFINE FIELD OVERWRITE password_hash ON TABLE user TYPE string ASSERT $value != NONE
    PERMISSIONS FOR select WHERE $auth.id = id;
DEFINE FIELD OVERWRITE password_must_change ON TABLE user TYPE bool DEFAULT false;
DEFINE FIELD OVERWRITE first_name ON TABLE user TYPE string;
DEFINE FIELD OVERWRITE last_name ON TABLE user TYPE string;
DEFINE FIELD OVERWRITE phone ON TABLE user TYPE option<string>;
DEFINE FIELD OVERWRITE primary_tenant ON TABLE user TYPE record<tenant>;
DEFINE FIELD OVERWRITE accessible_tenants ON TABLE user TYPE array<record<tenant>> DEFAULT [];
DEFINE FIELD OVERWRITE is_active ON TABLE user TYPE bool DEFAULT true;
DEFINE FIELD OVERWRITE last_login ON TABLE user TYPE option<datetime>;
DEFINE FIELD OVERWRITE password_changed_at ON TABLE user TYPE option<datetime>;
DEFINE FIELD OVERWRITE created_at ON TABLE user TYPE datetime DEFAULT time::now();
DEFINE FIELD OVERWRITE updated_at ON TABLE user TYPE datetime DEFAULT time::now();
DEFINE TABLE OVERWRITE user_role SCHEMAFULL
    PERMISSIONS 
        FOR select WHERE $auth.id = user OR
                        fn::has_permission(<string>$auth.id, 'role.view_all', NONE) OR
                        fn::has_permission(<string>$auth.id, 'role.view_own_tenant', <string>tenant)
        FOR create, update WHERE fn::has_permission(<string>$auth.id, 'role.assign_all', NONE) OR
                               fn::has_permission(<string>$auth.id, 'role.assign_own_tenant', <string>tenant) OR
                               fn::has_permission(<string>$auth.id, 'role.assign_customers', <string>tenant)
        FOR delete WHERE fn::has_permission(<string>$auth.id, 'role.assign_all', NONE);
DEFINE FIELD OVERWRITE user ON TABLE user_role TYPE record<user>;
DEFINE FIELD OVERWRITE role ON TABLE user_role TYPE record<role>;
DEFINE FIELD OVERWRITE tenant ON TABLE user_role TYPE record<tenant>;
DEFINE FIELD OVERWRITE granted_by ON TABLE user_role TYPE record<user>;
DEFINE FIELD OVERWRITE granted_at ON TABLE user_role TYPE datetime DEFAULT time::now();
DEFINE FIELD OVERWRITE expires_at ON TABLE user_role TYPE option<datetime>;
DEFINE FIELD OVERWRITE is_active ON TABLE user_role TYPE bool DEFAULT true;
